// Extract entity IDs from SuiteDash contacts
// Filter to llcs only (entity_type contains 'corp')
const contacts = $input.first().json.data || $input.first().json || [];
const llcEntityIds = [];

for (const contact of (Array.isArray(contacts) ? contacts : [contacts])) {
  const cf = contact.custom_fields || {};
  const entityType = (cf.entity_type || '').toLowerCase();
  if (entityType.includes('llc') || entityType.includes('limited liability company')) {
    const id = contact.id || cf.dos_number || `email:${contact.email}`;
    llcEntityIds.push(id);
  }
}

return [{ json: { entityIds: llcEntityIds, count: llcEntityIds.length, deadlineGroup: 'llcs' } }];

// Split reminder batch into individual send items
const reminders = $input.first().json.reminders || [];
const items = [];

for (const r of reminders) {
  for (const rem of r.reminders) {
    items.push({
      json: {
        entityId: r.entityId,
        entityName: r.entityName,
        entityType: r.entityType,
        email: r.email,
        plan: r.plan,
        deadline: r.deadline,
        daysUntilDeadline: r.daysUntilDeadline,
        daysBeforeDeadline: rem.daysBeforeDeadline,
        priority: rem.priority,
        filingMethod: r.filingMethod,
        riskLevel: r.riskLevel
      }
    });
  }
}

return items;
